import type { MappedObject } from './helpers/mapped-object.js';

/**
 * API config for a chart zoom interaction
 * @public
 */
export interface ChartZoomConfig {
  /** Enables a specific zoom interaction on the chart. */
  enabled?: boolean;
}

/**
 * Type of event when performing a zoom action that triggers a change in the domain
 * @public
 */
export type ZoomChangeType =
  | 'reset'
  | 'zoom-x'
  | 'panning'
  | 'zoom-in'
  | 'zoom-out'
  | 'zoom-to-fit';

/**
 * @internal
 */
export const ZOOM_CHANGE_TYPE = Object.freeze<MappedObject<ZoomChangeType>>({
  Reset: 'reset',
  /**
   * @deprecated ZoomX is deprecated, please use `<[Chart].Zoom/>`  instead.
   */
  ZoomX: 'zoom-x',
  Panning: 'panning',
  ZoomIn: 'zoom-in',
  ZoomToFit: 'zoom-to-fit',
  ZoomOut: 'zoom-out',
});

/**
 * @internal
 */
export type DownloadData = 'download';

/**
 * @internal
 */
export type Intent = 'intent';

/** All charts interactions and modes there are
 * @internal
 */
export type ChartInteractionModes = ZoomChangeType | DownloadData | Intent;

/**
 * Zoom in and Zoom out toolbar interactions
 * @internal
 */
export type ZoomInZoomOut = Extract<
  ChartInteractionModes,
  'zoom-in' | 'zoom-out'
>;

/**
 * Type of exposed zoom actions
 * @internal
 */
export type ExposedZoomActions = Extract<
  ChartInteractionModes,
  ZoomInZoomOut | 'reset'
>;

export const ZOOM_ACTIONS = Object.freeze<MappedObject<ExposedZoomActions>>({
  ZoomIn: 'zoom-in',
  ZoomOut: 'zoom-out',
  Reset: 'reset',
});

/**
 * @public
 */
export interface ProgrammaticZoomHandlers {
  /** Activates the explore mode in the chart. */
  exploreMode: () => void;
  /** Activates the pan mode in the chart. */
  panMode: () => void;
  /** Activates the zoom mode in the chart. */
  zoomMode: () => void;
  /** Performs zoom in action on the domain */
  zoomIn: () => void;
  /** Performs zoom out action on the domain */
  zoomOut: () => void;
  /** Reset the domain to the default  */
  reset: () => void;
}
